// ---------------------------------------------------------------------------
// Shared TypeScript types mirroring Rust IPC structs
// This is the single source of truth for all frontend ↔ Tauri boundary types.
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// RPC Commands (frontend → GSD process via stdin)
// Mirrors: src-tauri/src/gsd_rpc.rs — RpcCommand
// serde(tag = "type", rename_all = "snake_case")
// ---------------------------------------------------------------------------

export type RpcCommand =
  | { type: "prompt"; text: string }
  | { type: "steer"; text: string }
  | { type: "abort" }
  | { type: "get_state" }
  | { type: "set_model"; model: string }
  | { type: "get_available_models" }
  | { type: "get_session_stats" }
  | { type: "get_messages" }
  | { type: "new_session" };

// ---------------------------------------------------------------------------
// RPC Events (GSD process → frontend via stdout)
// Mirrors: src-tauri/src/gsd_rpc.rs — RpcEvent
// serde(tag = "type", rename_all = "snake_case")
// Field names stay snake_case in JSON (no rename_all on struct fields).
// ---------------------------------------------------------------------------

export type RpcEvent =
  | { type: "agent_start"; session_id: string }
  | { type: "agent_end"; session_id: string }
  | { type: "assistant_message"; content: string; done: boolean }
  | { type: "tool_execution_start"; tool: string; id: string }
  | { type: "tool_execution_end"; tool: string; id: string; success: boolean }
  | {
      type: "extension_ui_request";
      request_id: string;
      kind: string;
      payload: unknown;
    }
  | { type: "session_state_changed"; payload: unknown }
  | { type: "error"; message: string };

// ---------------------------------------------------------------------------
// Query types
// Mirrors: src-tauri/src/gsd_query.rs
// serde(rename_all = "camelCase")
// ---------------------------------------------------------------------------

/** Snapshot of GSD project state, returned by `query_gsd_state` command. */
export interface QuerySnapshot {
  currentMilestone: string | null;
  activeTasks: number;
  totalCost: number;
}

/** A discovered GSD project directory. */
export interface ProjectInfo {
  id: string;
  name: string;
  path: string;
}

/** A project stored in the persistent registry. */
export interface SavedProject {
  id: string;
  name: string;
  path: string;
  description: string | null;
  addedAt: string;
}

/** Extended project info for gallery display. Built client-side from ProjectInfo + QuerySnapshot. */
export interface ProjectDisplayInfo extends ProjectInfo {
  status: "active" | "paused" | "idle";
  currentMilestone: string | null;
  totalCost: number;
  progress: number; // 0-100
  lastActivity: string | null; // ISO timestamp or null
}

// ---------------------------------------------------------------------------
// Milestone / Slice / Task tree types (for progress dashboard & roadmap)
// ---------------------------------------------------------------------------

export type CompletionStatus = "done" | "in-progress" | "pending" | "blocked";
export type RiskLevel = "low" | "medium" | "high";

export interface TaskInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  cost: number;
  duration: string | null;
}

export interface SliceInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  risk: RiskLevel;
  cost: number;
  progress: number; // 0-100
  tasks: TaskInfo[];
  depends: string[];
}

export interface MilestoneInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  cost: number;
  progress: number; // 0-100
  slices: SliceInfo[];
}

// ---------------------------------------------------------------------------
// Cost data types (for cost overview charts)
// ---------------------------------------------------------------------------

export interface CostByPhase {
  phase: string;
  cost: number;
}

export interface CostByModel {
  model: string;
  cost: number;
}

export interface CostData {
  totalCost: number;
  budgetCeiling: number | null;
  byPhase: CostByPhase[];
  byModel: CostByModel[];
  bySlice: { sliceId: string; title: string; cost: number }[];
}

// ---------------------------------------------------------------------------
// Session types (for session browser)
// ---------------------------------------------------------------------------

export interface SessionInfo {
  id: string;
  name: string;
  messageCount: number;
  cost: number;
  createdAt: string; // ISO
  lastActiveAt: string; // ISO
  preview: string; // first message preview
  parentId: string | null;
  isActive: boolean;
}

// ---------------------------------------------------------------------------
// Process event payloads
// Mirrors: src-tauri/src/gsd_process.rs
// No rename_all — fields are single-word, so no casing issue.
// ---------------------------------------------------------------------------

/** Payload emitted as a `gsd-event` Tauri event for each JSONL line from stdout. */
export interface GsdEventPayload {
  raw: string;
  timestamp: number;
}

/** Payload emitted as `gsd-process-exit`. */
export interface GsdExitPayload {
  code: number | null;
  timestamp: number;
}

/** Payload emitted as `gsd-process-error`. */
export interface GsdErrorPayload {
  message: string;
  timestamp: number;
}

// ---------------------------------------------------------------------------
// File watcher payload
// Mirrors: src-tauri/src/gsd_watcher.rs
// serde(rename_all = "camelCase") — but all fields are single-word anyway.
// ---------------------------------------------------------------------------

/** Payload for `gsd-file-changed` events. */
export interface GsdFileChangedPayload {
  path: string;
  kind: string;
  timestamp: number;
}

// ---------------------------------------------------------------------------
// Session state
// ---------------------------------------------------------------------------

/** Possible states of the GSD agent session. */
export type SessionState =
  | "idle"
  | "connecting"
  | "connected"
  | "streaming"
  | "disconnected"
  | "error";

// GSD Client — IPC abstraction layer
// This is the ONLY file in the frontend that may import @tauri-apps/api (D005).

import { invoke } from "@tauri-apps/api/core";
import { listen } from "@tauri-apps/api/event";

import type {
  RpcCommand,
  QuerySnapshot,
  ProjectInfo,
  SavedProject,
  MilestoneInfo,
  GsdEventPayload,
  GsdExitPayload,
  GsdErrorPayload,
  GsdFileChangedPayload,
} from "@/lib/types";

// Re-export types so downstream consumers import from gsd-client (D005 boundary)
export type {
  RpcCommand,
  QuerySnapshot,
  ProjectInfo,
  SavedProject,
  MilestoneInfo,
  GsdEventPayload,
  GsdExitPayload,
  GsdErrorPayload,
  GsdFileChangedPayload,
} from "@/lib/types";

// ---------------------------------------------------------------------------
// GsdClient interface
// ---------------------------------------------------------------------------

export interface GsdClient {
  // Commands (invoke-based)
  startSession: (projectPath: string) => Promise<void>;
  stopSession: () => Promise<void>;
  sendCommand: (command: RpcCommand) => Promise<void>;
  queryState: (projectPath: string) => Promise<QuerySnapshot>;
  listProjects: (scanPath: string) => Promise<ProjectInfo[]>;
  startFileWatcher: (projectPath: string) => Promise<void>;
  stopFileWatcher: () => Promise<void>;
  // GSD parser
  parseProjectMilestones: (projectPath: string) => Promise<MilestoneInfo[]>;
  // Project registry
  getSavedProjects: () => Promise<SavedProject[]>;
  addProject: (projectPath: string, description?: string) => Promise<SavedProject>;
  removeProject: (projectId: string) => Promise<void>;
  // Event listeners (listen-based) — return unlisten functions
  onGsdEvent: (
    handler: (payload: GsdEventPayload) => void,
  ) => Promise<() => void>;
  onProcessExit: (
    handler: (payload: GsdExitPayload) => void,
  ) => Promise<() => void>;
  onProcessError: (
    handler: (payload: GsdErrorPayload) => void,
  ) => Promise<() => void>;
  onFileChanged: (
    handler: (payload: GsdFileChangedPayload) => void,
  ) => Promise<() => void>;
}

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

export function createGsdClient(): GsdClient {
  return {
    // ---- invoke-based commands ----
    startSession: (projectPath: string) =>
      invoke("start_gsd_session", { projectPath }),

    stopSession: () => invoke("stop_gsd_session"),

    sendCommand: (command: RpcCommand) =>
      invoke("send_gsd_command", { command: JSON.stringify(command) }),

    queryState: (projectPath: string) =>
      invoke<QuerySnapshot>("query_gsd_state", { projectPath }),

    listProjects: (scanPath: string) =>
      invoke<ProjectInfo[]>("list_projects", { scanPath }),

    startFileWatcher: (projectPath: string) =>
      invoke("start_file_watcher", { projectPath }),

    stopFileWatcher: () => invoke("stop_file_watcher"),

    // ---- GSD parser ----
    parseProjectMilestones: (projectPath: string) =>
      invoke<MilestoneInfo[]>("parse_project_milestones", { projectPath }),

    // ---- project registry ----
    getSavedProjects: () =>
      invoke<SavedProject[]>("get_saved_projects"),

    addProject: (projectPath: string, description?: string) =>
      invoke<SavedProject>("add_project", { projectPath, description: description ?? null }),

    removeProject: (projectId: string) =>
      invoke("remove_project", { projectId }),

    // ---- listen-based event subscriptions ----
    onGsdEvent: (handler) =>
      listen<GsdEventPayload>("gsd-event", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),

    onProcessExit: (handler) =>
      listen<GsdExitPayload>("gsd-process-exit", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),

    onProcessError: (handler) =>
      listen<GsdErrorPayload>("gsd-process-error", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),

    onFileChanged: (handler) =>
      listen<GsdFileChangedPayload>("gsd-file-changed", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),
  };
}

import { create } from "zustand";
import { createGsdClient } from "@/services/gsd-client";
import type { SavedProject } from "@/lib/types";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface ProjectState {
  projects: SavedProject[];
  activeProject: SavedProject | null;
  isLoading: boolean;
  error: string | null;

  // Actions
  loadProjects: () => Promise<void>;
  addProject: (projectPath: string, description?: string) => Promise<SavedProject>;
  removeProject: (projectId: string) => Promise<void>;
  selectProject: (project: SavedProject) => void;
  clearError: () => void;
}

// ---------------------------------------------------------------------------
// Store
// ---------------------------------------------------------------------------

const client = createGsdClient();

export const useProjectStore = create<ProjectState>()((set, get) => ({
  projects: [],
  activeProject: null,
  isLoading: false,
  error: null,

  loadProjects: async () => {
    set({ isLoading: true, error: null });
    try {
      const projects = await client.getSavedProjects();
      set({ projects, isLoading: false });
    } catch (err) {
      set({
        isLoading: false,
        error: err instanceof Error ? err.message : String(err),
      });
    }
  },

  addProject: async (projectPath: string, description?: string) => {
    set({ error: null });
    try {
      const saved = await client.addProject(projectPath, description);
      // Reload the full list to stay in sync
      const projects = await client.getSavedProjects();
      set({ projects });
      return saved;
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      set({ error: message });
      throw new Error(message);
    }
  },

  removeProject: async (projectId: string) => {
    set({ error: null });
    try {
      await client.removeProject(projectId);
      const { activeProject } = get();
      const projects = await client.getSavedProjects();
      set({
        projects,
        activeProject:
          activeProject?.id === projectId ? null : activeProject,
      });
    } catch (err) {
      set({
        error: err instanceof Error ? err.message : String(err),
      });
    }
  },

  selectProject: (project: SavedProject) => {
    set({ activeProject: project });
  },

  clearError: () => set({ error: null }),
}));

import { render, type RenderOptions } from "@testing-library/react";
import { MemoryRouter, type MemoryRouterProps } from "react-router-dom";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { beforeEach, vi } from "vitest";
import { ThemeProvider } from "@/components/theme-provider";

/**
 * Mock matchMedia for jsdom — required by ThemeProvider (K009).
 * Call this in a beforeEach block or at module scope before rendering.
 */
export function setupMatchMediaMock() {
  Object.defineProperty(window, "matchMedia", {
    writable: true,
    value: vi.fn().mockImplementation((query: string) => ({
      matches: false,
      media: query,
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
  });
}

// Auto-setup matchMedia mock before each test in any file that imports this module
beforeEach(() => {
  setupMatchMediaMock();
});

interface RenderWithProvidersOptions extends Omit<RenderOptions, "wrapper"> {
  initialRoute?: string;
  routes?: MemoryRouterProps["initialEntries"];
}

/**
 * Renders a component wrapped in QueryClientProvider + ThemeProvider + MemoryRouter.
 * - `initialRoute`: shorthand for a single initial entry (default: "/")
 * - `routes`: full initialEntries array for MemoryRouter (overrides initialRoute)
 */
export function renderWithProviders(
  ui: React.ReactElement,
  { initialRoute = "/", routes, ...options }: RenderWithProvidersOptions = {},
) {
  const initialEntries = routes ?? [initialRoute];
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false } },
  });

  function Wrapper({ children }: { children: React.ReactNode }) {
    return (
      <QueryClientProvider client={queryClient}>
        <ThemeProvider defaultTheme="system" storageKey="gsd-gui-theme-test">
          <MemoryRouter initialEntries={initialEntries}>{children}</MemoryRouter>
        </ThemeProvider>
      </QueryClientProvider>
    );
  }

  return render(ui, { wrapper: Wrapper, ...options });
}

// Re-export everything from testing-library for convenience
export * from "@testing-library/react";
export { default as userEvent } from "@testing-library/user-event";

import { useQuery } from "@tanstack/react-query";
import { createGsdClient } from "@/services/gsd-client";
import type { QuerySnapshot } from "@/lib/types";

const client = createGsdClient();

/**
 * Hook that polls GSD headless query state for a project.
 * Returns a TanStack Query result with auto-refresh every 2 seconds.
 * Disabled when projectPath is null/undefined.
 */
export function useGsdState(projectPath: string | null | undefined) {
  return useQuery<QuerySnapshot>({
    queryKey: ["gsd-state", projectPath],
    queryFn: () => client.queryState(projectPath!),
    enabled: !!projectPath,
    refetchInterval: 2000,
    staleTime: 1000,
  });
}

import { describe, it, expect, beforeEach, vi } from "vitest";
import { renderHook, waitFor } from "@testing-library/react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import React from "react";

const { mockClient } = vi.hoisted(() => {
  const mockClient = {
    startSession: vi.fn(),
    stopSession: vi.fn(),
    sendCommand: vi.fn(),
    queryState: vi.fn().mockResolvedValue({
      currentMilestone: "M001",
      activeTasks: 3,
      totalCost: 1.5,
    }),
    listProjects: vi.fn().mockResolvedValue([]),
    startFileWatcher: vi.fn(),
    stopFileWatcher: vi.fn(),
    onGsdEvent: vi.fn().mockResolvedValue(vi.fn()),
    onProcessExit: vi.fn().mockResolvedValue(vi.fn()),
    onProcessError: vi.fn().mockResolvedValue(vi.fn()),
    onFileChanged: vi.fn().mockResolvedValue(vi.fn()),
  };
  return { mockClient };
});

vi.mock("@/services/gsd-client", () => ({
  createGsdClient: () => mockClient,
}));

import { useGsdState } from "./use-gsd-state";

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false } },
  });
  return ({ children }: { children: React.ReactNode }) =>
    React.createElement(QueryClientProvider, { client: queryClient }, children);
}

describe("useGsdState", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("returns loading state initially", () => {
    const { result } = renderHook(() => useGsdState("/project"), {
      wrapper: createWrapper(),
    });
    expect(result.current.isLoading).toBe(true);
  });

  it("returns snapshot data on success", async () => {
    const { result } = renderHook(() => useGsdState("/project"), {
      wrapper: createWrapper(),
    });
    await waitFor(() => expect(result.current.isSuccess).toBe(true));
    expect(result.current.data).toEqual({
      currentMilestone: "M001",
      activeTasks: 3,
      totalCost: 1.5,
    });
    expect(mockClient.queryState).toHaveBeenCalledWith("/project");
  });

  it("returns null data when no project path", async () => {
    const { result } = renderHook(() => useGsdState(null), {
      wrapper: createWrapper(),
    });
    // Query should be disabled when path is null
    expect(result.current.fetchStatus).toBe("idle");
  });

  it("returns error on failure", async () => {
    mockClient.queryState.mockRejectedValueOnce(new Error("query failed"));
    const { result } = renderHook(() => useGsdState("/bad"), {
      wrapper: createWrapper(),
    });
    await waitFor(() => expect(result.current.isError).toBe(true));
    expect(result.current.error).toBeTruthy();
  });
});

import { describe, it, expect, beforeEach, vi } from "vitest";

const { mockClient } = vi.hoisted(() => {
  const mockClient = {
    startSession: vi.fn(),
    stopSession: vi.fn(),
    sendCommand: vi.fn(),
    queryState: vi.fn(),
    listProjects: vi.fn().mockResolvedValue([]),
    startFileWatcher: vi.fn(),
    stopFileWatcher: vi.fn(),
    getSavedProjects: vi.fn().mockResolvedValue([]),
    addProject: vi.fn(),
    removeProject: vi.fn(),
    onGsdEvent: vi.fn().mockResolvedValue(vi.fn()),
    onProcessExit: vi.fn().mockResolvedValue(vi.fn()),
    onProcessError: vi.fn().mockResolvedValue(vi.fn()),
    onFileChanged: vi.fn().mockResolvedValue(vi.fn()),
  };
  return { mockClient };
});

vi.mock("@/services/gsd-client", () => ({
  createGsdClient: () => mockClient,
}));

import { useProjectStore } from "./project-store";
import type { SavedProject } from "@/lib/types";

const makeProject = (id: string, name: string): SavedProject => ({
  id,
  name,
  path: `/projects/${name}`,
  description: null,
  addedAt: "1234567890",
});

describe("project-store", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    useProjectStore.setState({
      projects: [],
      activeProject: null,
      isLoading: false,
      error: null,
    });
  });

  describe("initial state", () => {
    it("has correct defaults", () => {
      const state = useProjectStore.getState();
      expect(state.projects).toEqual([]);
      expect(state.activeProject).toBeNull();
      expect(state.isLoading).toBe(false);
      expect(state.error).toBeNull();
    });
  });

  describe("loadProjects", () => {
    it("loads saved projects from registry", async () => {
      const projects = [makeProject("p1", "alpha"), makeProject("p2", "beta")];
      mockClient.getSavedProjects.mockResolvedValueOnce(projects);

      await useProjectStore.getState().loadProjects();

      expect(useProjectStore.getState().projects).toEqual(projects);
      expect(useProjectStore.getState().isLoading).toBe(false);
      expect(mockClient.getSavedProjects).toHaveBeenCalled();
    });

    it("sets loading state during fetch", async () => {
      let resolve: (v: SavedProject[]) => void;
      mockClient.getSavedProjects.mockReturnValueOnce(
        new Promise<SavedProject[]>((r) => { resolve = r; }),
      );

      const promise = useProjectStore.getState().loadProjects();
      expect(useProjectStore.getState().isLoading).toBe(true);

      resolve!([]);
      await promise;
      expect(useProjectStore.getState().isLoading).toBe(false);
    });

    it("sets error on failure", async () => {
      mockClient.getSavedProjects.mockRejectedValueOnce(new Error("disk error"));
      await useProjectStore.getState().loadProjects();
      expect(useProjectStore.getState().error).toBe("disk error");
      expect(useProjectStore.getState().isLoading).toBe(false);
    });
  });

  describe("addProject", () => {
    it("adds a project and reloads the list", async () => {
      const saved = makeProject("p1", "new-project");
      mockClient.addProject.mockResolvedValueOnce(saved);
      mockClient.getSavedProjects.mockResolvedValueOnce([saved]);

      const result = await useProjectStore.getState().addProject("/projects/new-project");

      expect(result).toEqual(saved);
      expect(mockClient.addProject).toHaveBeenCalledWith("/projects/new-project", undefined);
      expect(useProjectStore.getState().projects).toEqual([saved]);
    });

    it("passes description when provided", async () => {
      const saved = makeProject("p1", "described");
      mockClient.addProject.mockResolvedValueOnce(saved);
      mockClient.getSavedProjects.mockResolvedValueOnce([saved]);

      await useProjectStore.getState().addProject("/path", "My project");
      expect(mockClient.addProject).toHaveBeenCalledWith("/path", "My project");
    });

    it("sets error and throws on failure", async () => {
      mockClient.addProject.mockRejectedValueOnce(new Error("no .gsd/ found"));

      await expect(
        useProjectStore.getState().addProject("/bad"),
      ).rejects.toThrow("no .gsd/ found");

      expect(useProjectStore.getState().error).toBe("no .gsd/ found");
    });
  });

  describe("removeProject", () => {
    it("removes a project and reloads the list", async () => {
      const p1 = makeProject("p1", "alpha");
      const p2 = makeProject("p2", "beta");
      useProjectStore.setState({ projects: [p1, p2], activeProject: p1 });

      mockClient.removeProject.mockResolvedValueOnce(undefined);
      mockClient.getSavedProjects.mockResolvedValueOnce([p2]);

      await useProjectStore.getState().removeProject("p1");

      expect(mockClient.removeProject).toHaveBeenCalledWith("p1");
      expect(useProjectStore.getState().projects).toEqual([p2]);
      // Active project was removed, so it should be cleared
      expect(useProjectStore.getState().activeProject).toBeNull();
    });

    it("preserves activeProject if a different project is removed", async () => {
      const p1 = makeProject("p1", "alpha");
      const p2 = makeProject("p2", "beta");
      useProjectStore.setState({ projects: [p1, p2], activeProject: p1 });

      mockClient.removeProject.mockResolvedValueOnce(undefined);
      mockClient.getSavedProjects.mockResolvedValueOnce([p1]);

      await useProjectStore.getState().removeProject("p2");

      expect(useProjectStore.getState().activeProject).toEqual(p1);
    });
  });

  describe("selectProject", () => {
    it("sets active project", () => {
      const project = makeProject("p1", "alpha");
      useProjectStore.getState().selectProject(project);
      expect(useProjectStore.getState().activeProject).toEqual(project);
    });
  });

  describe("clearError", () => {
    it("clears the error state", () => {
      useProjectStore.setState({ error: "something broke" });
      useProjectStore.getState().clearError();
      expect(useProjectStore.getState().error).toBeNull();
    });
  });
});

